import React from 'react';
import { Line } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

const MLPerformanceChart = () => {
  const data = {
    labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    datasets: [
      {
        label: 'Precision',
        data: [92, 93, 91, 94, 95, 94],
        borderColor: '#34d399',
        backgroundColor: 'rgba(52, 211, 153, 0.5)',
        tension: 0.4,
      },
      {
        label: 'Recall',
        data: [88, 89, 91, 90, 92, 93],
        borderColor: '#60a5fa',
        backgroundColor: 'rgba(96, 165, 250, 0.5)',
        tension: 0.4,
      },
      {
        label: 'F1 Score',
        data: [90, 91, 91, 92, 93, 93.5],
        borderColor: '#fbbf24',
        backgroundColor: 'rgba(251, 191, 36, 0.5)',
        tension: 0.4,
      },
    ],
  };

  const options = {
    responsive: true,
    plugins: {
      legend: {
        position: 'bottom',
        labels: {
          color: '#9ca3af',
        },
      },
      title: {
        display: true,
        text: 'ML Model Performance Over Time',
        color: '#d1d5db',
        align: 'start',
        font: {
          size: 16,
        },
      },
    },
    scales: {
      y: {
        min: 80,
        max: 100,
        ticks: {
          color: '#9ca3af',
          callback: function(value) {
            return value + '%';
          }
        },
        grid: {
          color: '#374151',
        },
      },
      x: {
        ticks: {
          color: '#9ca3af',
        },
        grid: {
          display: false,
        },
      },
    },
  };

  return (
    <div style={{ backgroundColor: '#1f2937', padding: '1.5rem', borderRadius: '0.5rem' }}>
      <Line options={options} data={data} />
    </div>
  );
};

export default MLPerformanceChart;
